// Min: -0.1, Max: 56.8

const ELEV_SCALE = 8 / 47;

const X_MIN = -50;
const X_MAX = 50;
const Z_MAX = 50;
const Z_MIN = -50;

export function getElevation(x: number, z: number): number {
  const gx = ((x - X_MIN) / (X_MAX - X_MIN)) * (GRID_SIZE - 1);
  const gz = ((Z_MAX - z) / (Z_MAX - Z_MIN)) * (GRID_SIZE - 1);

  if (gx < 0 || gx > GRID_SIZE - 1 || gz < 0 || gz > GRID_SIZE - 1) return 0;
  const xi = Math.max(0, Math.min(GRID_SIZE - 2, Math.floor(gx)));
  const zi = Math.max(0, Math.min(GRID_SIZE - 2, Math.floor(gz)));
  const tx = Math.max(0, Math.min(1, gx - xi));
  const tz = Math.max(0, Math.min(1, gz - zi));

  const e00 = ELEVATIONS[zi * GRID_SIZE + xi];
  const e10 = ELEVATIONS[zi * GRID_SIZE + xi + 1];
  const e01 = ELEVATIONS[(zi + 1) * GRID_SIZE + xi];
  const e11 = ELEVATIONS[(zi + 1) * GRID_SIZE + xi + 1];

  const e = e00 * (1 - tx) * (1 - tz) + e10 * tx * (1 - tz) + e01 * (1 - tx) * tz + e11 * tx * tz;

  return Math.max(0, e) * ELEV_SCALE;
}
